import json
import math
import os
import struct
import sys


def sub(a, b):
    return (a[0]-b[0], a[1]-b[1], a[2]-b[2])

def cross(a, b):
    return (
        a[1]*b[2]-a[2]*b[1],
        a[2]*b[0]-a[0]*b[2],
        a[0]*b[1]-a[1]*b[0],
    )

def dot(a, b):
    return a[0]*b[0] + a[1]*b[1] + a[2]*b[2]

def mag(v):
    return math.sqrt(dot(v, v))

def norm(v):
    m = mag(v)
    if m < 1e-12:
        return (0.0, 0.0, 0.0)
    return (v[0]/m, v[1]/m, v[2]/m)

def tri_area(v1, v2, v3):
    return 0.5 * mag(cross(sub(v2, v1), sub(v3, v1)))

def is_ascii_stl(path):
    with open(path, 'rb') as f:
        head = f.read(512)
    if len(head) < 6:
        return False
    try:
        text = head.decode('ascii', errors='ignore').lstrip()
    except Exception:
        return False
    return text.startswith('solid') and b'facet' in head

def parse_ascii(path):
    tris = []
    issues = []
    with open(path, 'r', errors='replace') as fh:
        lines = fh.readlines()
    i = 0
    while i < len(lines):
        line = lines[i].strip()
        if line.startswith('facet normal'):
            parts = line.split()
            try:
                dn = (float(parts[2]), float(parts[3]), float(parts[4]))
            except Exception:
                issues.append(f'malformed facet normal at line {i+1}')
                i += 1
                continue
            verts = []
            i += 1
            while i < len(lines) and lines[i].strip() == '':
                i += 1
            if i < len(lines) and lines[i].strip() == 'outer loop':
                i += 1
                while i < len(lines) and len(verts) < 3:
                    s = lines[i].strip()
                    if s.startswith('vertex'):
                        p = s.split()
                        try:
                            verts.append((float(p[1]), float(p[2]), float(p[3])))
                        except Exception:
                            issues.append(f'malformed vertex at line {i+1}')
                    i += 1
            if len(verts) == 3:
                tris.append((dn, verts))
            else:
                issues.append(f'incomplete triangle near line {i+1}')
            continue
        i += 1
    return tris, issues

def parse_binary(path):
    tris = []
    issues = []
    with open(path, 'rb') as f:
        data = f.read()
    if len(data) < 84:
        return [], ['file too short for binary STL']
    count = struct.unpack('<I', data[80:84])[0]
    expected = 84 + 50 * count
    if len(data) != expected:
        issues.append(f'binary size mismatch: header count={count}, bytes={len(data)}, expected={expected}')
        count = max(0, min(count, (len(data)-84)//50))
    off = 84
    for _ in range(count):
        rec = data[off:off+50]
        if len(rec) < 50:
            issues.append('truncated triangle record')
            break
        vals = struct.unpack('<12fH', rec)
        dn = (vals[0], vals[1], vals[2])
        v1 = (vals[3], vals[4], vals[5])
        v2 = (vals[6], vals[7], vals[8])
        v3 = (vals[9], vals[10], vals[11])
        tris.append((dn, [v1, v2, v3]))
        off += 50
    return tris, issues

def validate(path):
    if is_ascii_stl(path):
        tris, issues = parse_ascii(path)
        fmt = 'ascii'
    else:
        tris, issues = parse_binary(path)
        fmt = 'binary'
    edge_count = {}
    degenerate = 0
    inverted = 0
    for dn, verts in tris:
        area = tri_area(*verts)
        if area < 1e-12:
            degenerate += 1
        rounded = [tuple(round(c, 6) for c in v) for v in verts]
        for j in range(3):
            e = tuple(sorted((rounded[j], rounded[(j+1)%3])))
            edge_count[e] = edge_count.get(e, 0) + 1
        n = cross(sub(verts[1], verts[0]), sub(verts[2], verts[0]))
        if mag(n) >= 1e-12 and mag(dn) >= 1e-12:
            if dot(norm(dn), norm(n)) < -0.99:
                inverted += 1
    open_edges = sum(1 for c in edge_count.values() if c == 1)
    nonmanifold_edges = sum(1 for c in edge_count.values() if c > 2)
    if not tris:
        issues.append('no valid faces found')
    if open_edges:
        issues.append(f'mesh has {open_edges} open edge(s)')
    if nonmanifold_edges:
        issues.append(f'mesh has {nonmanifold_edges} non-manifold edge(s)')
    if degenerate:
        issues.append(f'mesh has {degenerate} degenerate triangle(s)')
    if inverted:
        issues.append(f'mesh has {inverted} inverted declared normal(s)')
    area = sum(tri_area(*verts) for _, verts in tris)
    return {
        'format': fmt,
        'valid': not issues,
        'triangle_count': len(tris),
        'surface_area': round(area, 6),
        'issues': issues,
    }

if __name__ == '__main__':
    if len(sys.argv) < 2:
        print(json.dumps({'error': 'usage'}))
        sys.exit(1)
    print(json.dumps(validate(sys.argv[1])))

